export type ShenqiGodName = keyof typeof SHENQI_EFFECTS;

export function getShenqiDescription(name: ShenqiGodName): string {
  const effect = SHENQI_EFFECTS[name];
  return `${effect.日常效果}\n${effect.六维加成}`;
}

export function applyCanonicalShenqiEffects(data: {
  古神列表?: Record<string, { 神契技能?: string; 神契描述?: string }>;
}): boolean {
  let changed = false;

  for (const [name, effect] of Object.entries(SHENQI_EFFECTS)) {
    const god = data.古神列表?.[name];
    if (!god) continue;

    const description = `${effect.日常效果}\n${effect.六维加成}`;
    if (god.神契技能 !== effect.技能) {
      god.神契技能 = effect.技能;
      changed = true;
    }
    if (god.神契描述 !== description) {
      god.神契描述 = description;
      changed = true;
    }
  }

  return changed;
}
