export interface MapPoint {
  x: number;
  y: number;
}

export const WORLD_MAP_IMAGE_URL =
  'https://cdn.jsdelivr.net/gh/roikoni/my_blog_image/A%3A%5CSilly%20Tavern%E7%9B%B8%E5%85%B3%5C%E5%9B%BE%E5%BA%8A-%E6%88%91%E8%A2%AB%E7%8C%AB%E5%A8%98%E5%8C%85%E5%9B%B4%E4%BA%86!%E6%AD%A3%E5%BC%8F%E5%9C%B0%E5%9B%BE%E7%AC%AC%E4%B8%80%E7%89%88.jpeg';

export interface FixedMapLocation extends MapPoint {
  name: string;
  aliases: string[];
  region: string;
  type: string;
  radius?: number;
  color?: string;
  description?: string;
}

export interface FixedMapRegion extends MapPoint {
  name: string;
  aliases: string[];
}

export interface FixedMapData {
  version: number;
  defaultCenter: MapPoint;
  regions: FixedMapRegion[];
  locations: FixedMapLocation[];
}

export interface MapPolygonRegion {
  势力: string;
  颜色: string;
  透明度: number;
  描述: string;
  顶点: MapPoint[];
}

export interface MapRegionMatch extends MapPolygonRegion {
  name: string;
}

export type MapMatchSource =
  | 'mvu-coordinate'
  | 'fixed-exact'
  | 'fixed-alias'
  | 'relative-area'
  | 'region'
  | 'default';

export interface MapLocationMatch extends MapPoint {
  name: string;
  source: MapMatchSource;
}

function normalize(value: string): string {
  return value.trim().replace(/\s+/g, '').toLocaleLowerCase();
}

function phraseMatches(place: string, phrase: string): boolean {
  const target = normalize(phrase);
  if (!target) return false;

  const normalizedPlace = normalize(place);
  if (normalizedPlace === target) return true;

  const segments = place
    .split(/[·•/／、,，>＞—–-]+/)
    .map(normalize)
    .filter(Boolean);
  return segments.includes(target);
}

function longestMatch<T>(items: T[], terms: (item: T) => string[], place: string): T | undefined {
  return items
    .map(item => ({ item, length: Math.max(0, ...terms(item).filter(term => phraseMatches(place, term)).map(term => normalize(term).length)) }))
    .filter(candidate => candidate.length > 0)
    .sort((a, b) => b.length - a.length)[0]?.item;
}

type RelativeRelation = 'inside' | 'boundary' | 'outside';

interface RelativeQualifier {
  relation: RelativeRelation;
  direction: MapPoint | null;
}

type RelativeMapArea = FixedMapLocation | FixedMapRegion;

interface RelativeLocationReference {
  area: RelativeMapArea;
  qualifier: RelativeQualifier;
}

const LOCATION_TYPE_RADIUS: Record<string, number> = {
  都城: 1.4,
  城池: 1.05,
  城镇: 0.9,
  港口: 0.8,
  州域: 3.2,
  妖族领地: 4,
  古神领地: 2.4,
  正道宗门: 0.9,
  魔道宗门: 0.9,
  秘境: 0.85,
  禁地: 1.2,
  关隘: 0.7,
  管制区: 0.8,
  未明地点: 0.8,
};

function parseDirection(value: string): MapPoint | null {
  if (value.includes('东北')) return { x: Math.SQRT1_2, y: -Math.SQRT1_2 };
  if (value.includes('西北')) return { x: -Math.SQRT1_2, y: -Math.SQRT1_2 };
  if (value.includes('东南')) return { x: Math.SQRT1_2, y: Math.SQRT1_2 };
  if (value.includes('西南')) return { x: -Math.SQRT1_2, y: Math.SQRT1_2 };
  if (value.includes('东')) return { x: 1, y: 0 };
  if (value.includes('西')) return { x: -1, y: 0 };
  if (value.includes('南')) return { x: 0, y: 1 };
  if (value.includes('北')) return { x: 0, y: -1 };
  return null;
}

function parseRelativeQualifier(value: string): RelativeQualifier | null {
  const direction = parseDirection(value);
  if (/(城外|郊外|近郊|城郊|外围|外缘|境外|山门外|门外|谷外|宫外|宗外|以外|外海|附近|周边)/u.test(value)) {
    return { relation: 'outside', direction };
  }
  if (/(城门|山门|边缘|边界|边境|交界|入口|出口|关口|沿岸|岸边)/u.test(value)) {
    return { relation: 'boundary', direction };
  }
  if (/(城内|城中|城区|境内|山门内|门内|谷内|宫内|宗内|内部|深处|中心|腹地)/u.test(value)) {
    return { relation: 'inside', direction };
  }
  return direction ? { relation: 'inside', direction } : null;
}

function findRelativeLocationReference(place: string, fixedData: FixedMapData): RelativeLocationReference | null {
  const normalizedPlace = normalize(place);
  const areas = [
    ...fixedData.locations.map(area => ({ area, priority: 1 })),
    ...fixedData.regions.map(area => ({ area, priority: 0 })),
  ];
  const match = areas
    .flatMap(({ area, priority }) =>
      [area.name, ...area.aliases].map(term => {
        const normalizedTerm = normalize(term);
        return {
          area,
          priority,
          term: normalizedTerm,
          index: normalizedTerm.length >= 2 ? normalizedPlace.indexOf(normalizedTerm) : -1,
        };
      }),
    )
    .filter(candidate => candidate.index >= 0)
    .sort((a, b) => b.term.length - a.term.length || b.priority - a.priority)[0];
  if (!match) return null;

  const suffix = normalizedPlace.slice(match.index + match.term.length);
  const qualifier = parseRelativeQualifier(suffix);
  return qualifier ? { area: match.area, qualifier } : null;
}

function regionKey(value: string): string {
  return normalize(value).replaceAll('洲', '州');
}

function findLocationRegion(
  area: RelativeMapArea,
  regions: Record<string, MapPolygonRegion>,
): MapPolygonRegion | null {
  const names = new Set([area.name, ...area.aliases].map(regionKey));
  const match = Object.entries(regions).find(([name]) => names.has(regionKey(name)));
  return match ? match[1] : null;
}

function pointDistance(a: MapPoint, b: MapPoint): number {
  return Math.hypot(a.x - b.x, a.y - b.y);
}

function clampPercentage(value: number): number {
  return Math.min(100, Math.max(0, value));
}

function averagePoint(points: MapPoint[]): MapPoint {
  if (points.length === 0) return { x: 50, y: 50 };
  return {
    x: points.reduce((sum, point) => sum + point.x, 0) / points.length,
    y: points.reduce((sum, point) => sum + point.y, 0) / points.length,
  };
}

function directionFromPoint(center: MapPoint, point: MapPoint | null): MapPoint {
  if (!point) return { x: 1, y: 0 };
  const dx = point.x - center.x;
  const dy = point.y - center.y;
  const length = Math.hypot(dx, dy);
  return length > 0.001 ? { x: dx / length, y: dy / length } : { x: 1, y: 0 };
}

function directionMatches(point: MapPoint, center: MapPoint, direction: MapPoint | null): boolean {
  if (!direction) return true;
  const dx = point.x - center.x;
  const dy = point.y - center.y;
  const length = Math.hypot(dx, dy);
  return length > 0.001 && (dx * direction.x + dy * direction.y) / length >= 0.35;
}

function rayPolygonBoundaryDistance(center: MapPoint, direction: MapPoint, vertices: MapPoint[]): number | null {
  const cross = (a: MapPoint, b: MapPoint) => a.x * b.y - a.y * b.x;
  let nearest = Number.POSITIVE_INFINITY;

  vertices.forEach((start, index) => {
    const end = vertices[(index + 1) % vertices.length];
    const edge = { x: end.x - start.x, y: end.y - start.y };
    const denominator = cross(direction, edge);
    if (Math.abs(denominator) < 1e-8) return;

    const offset = { x: start.x - center.x, y: start.y - center.y };
    const distance = cross(offset, edge) / denominator;
    const segmentRatio = cross(offset, direction) / denominator;
    if (distance >= 0 && segmentRatio >= 0 && segmentRatio <= 1) nearest = Math.min(nearest, distance);
  });

  return Number.isFinite(nearest) ? nearest : null;
}

function distanceToSegment(point: MapPoint, start: MapPoint, end: MapPoint): number {
  const dx = end.x - start.x;
  const dy = end.y - start.y;
  const lengthSquared = dx * dx + dy * dy;
  if (lengthSquared === 0) return pointDistance(point, start);
  const ratio = Math.min(1, Math.max(0, ((point.x - start.x) * dx + (point.y - start.y) * dy) / lengthSquared));
  return pointDistance(point, { x: start.x + dx * ratio, y: start.y + dy * ratio });
}

function distanceToPolygon(point: MapPoint, vertices: MapPoint[]): number {
  return Math.min(
    ...vertices.map((start, index) => distanceToSegment(point, start, vertices[(index + 1) % vertices.length])),
  );
}

function relativeMatch(name: string, point: MapPoint): MapLocationMatch {
  return { name, x: clampPercentage(point.x), y: clampPercentage(point.y), source: 'relative-area' };
}

function resolvePolygonRelativeLocation(
  place: string,
  coordinates: MapPoint | null,
  area: RelativeMapArea,
  qualifier: RelativeQualifier,
  region: MapPolygonRegion,
): MapLocationMatch {
  const center = isPointInMapRegion(area, region.顶点) ? area : averagePoint(region.顶点);
  const direction = qualifier.direction ?? directionFromPoint(center, coordinates);
  const boundaryDistance = rayPolygonBoundaryDistance(center, direction, region.顶点)
    ?? Math.max(0.5, ...region.顶点.map(point => pointDistance(center, point)));

  if (coordinates && directionMatches(coordinates, center, qualifier.direction)) {
    const inside = isPointInMapRegion(coordinates, region.顶点);
    const edgeDistance = distanceToPolygon(coordinates, region.顶点);
    if (qualifier.relation === 'inside' && inside) return relativeMatch(place, coordinates);
    if (qualifier.relation === 'boundary' && edgeDistance <= Math.max(0.15, boundaryDistance * 0.16)) {
      return relativeMatch(place, coordinates);
    }
    if (
      qualifier.relation === 'outside'
      && !inside
      && edgeDistance <= Math.max(0.6, boundaryDistance * 0.8)
    ) {
      return relativeMatch(place, coordinates);
    }
  }

  const factor = qualifier.relation === 'inside' ? 0.62 : qualifier.relation === 'boundary' ? 0.97 : 1.24;
  let point = {
    x: center.x + direction.x * boundaryDistance * factor,
    y: center.y + direction.y * boundaryDistance * factor,
  };
  if (qualifier.relation === 'outside') {
    let attempt = 0;
    while (isPointInMapRegion(point, region.顶点) && attempt < 4) {
      const nextFactor = factor + (attempt + 1) * 0.22;
      point = {
        x: center.x + direction.x * boundaryDistance * nextFactor,
        y: center.y + direction.y * boundaryDistance * nextFactor,
      };
      attempt++;
    }
  }
  return relativeMatch(place, point);
}

function resolveCircularRelativeLocation(
  place: string,
  coordinates: MapPoint | null,
  area: RelativeMapArea,
  qualifier: RelativeQualifier,
): MapLocationMatch {
  const location = 'type' in area ? area : null;
  const radius = location?.radius ?? (location ? (LOCATION_TYPE_RADIUS[location.type] ?? 0.85) : 3);
  const direction = qualifier.direction ?? directionFromPoint(area, coordinates);

  if (coordinates && directionMatches(coordinates, area, qualifier.direction)) {
    const distance = pointDistance(coordinates, area);
    if (qualifier.relation === 'inside' && distance <= radius) return relativeMatch(place, coordinates);
    if (qualifier.relation === 'boundary' && Math.abs(distance - radius) <= Math.max(0.15, radius * 0.18)) {
      return relativeMatch(place, coordinates);
    }
    if (qualifier.relation === 'outside' && distance > radius && distance <= radius * 1.8) {
      return relativeMatch(place, coordinates);
    }
  }

  const factor = qualifier.relation === 'inside' ? 0.62 : qualifier.relation === 'boundary' ? 1 : 1.3;
  return relativeMatch(place, {
    x: area.x + direction.x * radius * factor,
    y: area.y + direction.y * radius * factor,
  });
}

export function resolveMapLocation(
  place: string,
  fixedData: FixedMapData,
): MapLocationMatch {
  const exact = longestMatch(fixedData.locations, item => [item.name], place);
  if (exact) return { name: exact.name, x: exact.x, y: exact.y, source: 'fixed-exact' };

  const alias = longestMatch(fixedData.locations, item => item.aliases, place);
  if (alias) return { name: alias.name, x: alias.x, y: alias.y, source: 'fixed-alias' };

  const region = longestMatch(fixedData.regions, item => [item.name, ...item.aliases], place);
  if (region) return { name: region.name, x: region.x, y: region.y, source: 'region' };

  return { name: place || '未知之地', ...fixedData.defaultCenter, source: 'default' };
}

export function hasValidMapCoordinates(value: unknown): value is MapPoint {
  if (!value || typeof value !== 'object') return false;
  const point = value as Partial<MapPoint>;
  return Number.isFinite(point.x) && Number.isFinite(point.y)
    && Number(point.x) >= 0 && Number(point.x) <= 100
    && Number(point.y) >= 0 && Number(point.y) <= 100;
}

/**
 * 已知固定地点使用地图标定坐标，避免模型估算的 MVU 坐标把角色标到同一地域的远处。
 * 荒野、路途等无法匹配固定地点的位置仍优先使用 MVU 坐标，保留自由移动精度。
 */
export function resolveCurrentMapLocation(
  place: string,
  coordinates: unknown,
  fixedData: FixedMapData,
  regions: Record<string, MapPolygonRegion> = {},
): MapLocationMatch {
  const mvuCoordinates = hasValidMapCoordinates(coordinates)
    ? { x: Number(coordinates.x), y: Number(coordinates.y) }
    : null;
  const relativeReference = findRelativeLocationReference(place, fixedData);
  if (relativeReference) {
    const { area, qualifier } = relativeReference;
    const region = findLocationRegion(area, regions);
    return region
      ? resolvePolygonRelativeLocation(place, mvuCoordinates, area, qualifier, region)
      : resolveCircularRelativeLocation(place, mvuCoordinates, area, qualifier);
  }

  const namedLocation = resolveMapLocation(place, fixedData);
  if (namedLocation.source === 'fixed-exact' || namedLocation.source === 'fixed-alias') {
    return namedLocation;
  }

  if (mvuCoordinates) {
    return {
      name: place || '未知之地',
      ...mvuCoordinates,
      source: 'mvu-coordinate',
    };
  }
  return namedLocation;
}

function polygonArea(vertices: MapPoint[]): number {
  if (vertices.length < 3) return Number.POSITIVE_INFINITY;
  return Math.abs(vertices.reduce((sum, point, index) => {
    const next = vertices[(index + 1) % vertices.length];
    return sum + point.x * next.y - next.x * point.y;
  }, 0) / 2);
}

export function isPointInMapRegion(point: MapPoint, vertices: MapPoint[]): boolean {
  if (vertices.length < 3) return false;
  let inside = false;
  for (let i = 0, j = vertices.length - 1; i < vertices.length; j = i++) {
    const a = vertices[i];
    const b = vertices[j];
    const crosses = (a.y > point.y) !== (b.y > point.y)
      && point.x < ((b.x - a.x) * (point.y - a.y)) / (b.y - a.y) + a.x;
    if (crosses) inside = !inside;
  }
  return inside;
}

/** 重叠区域优先返回面积更小的多边形，使城池、宗门等具体范围覆盖大洲区域。 */
export function resolveMapRegionAtPoint(
  point: MapPoint,
  regions: Record<string, MapPolygonRegion>,
): MapRegionMatch | null {
  const matches = Object.entries(regions)
    .filter(([, region]) => isPointInMapRegion(point, region.顶点))
    .sort(([, a], [, b]) => polygonArea(a.顶点) - polygonArea(b.顶点));
  const match = matches[0];
  return match ? { name: match[0], ...match[1] } : null;
}
