import { defineMvuDataStore } from '@util/mvu';
import { applyCanonicalShenqiEffects, SHENQI_EFFECTS } from '../_shared/shenqiEffects';
import { 结算已学习功法属性 } from '../_shared/techniqueAttributeBonus';
import { Schema } from './schema';

// 使用 -1（最新楼层）而非 getCurrentMessageId()，确保始终读取最新的变量数据，
// 不受状态栏 iframe 所在具体楼层的限制。加载旧存档时，将旧版复杂神契迁移为新版常驻效果。
const VARIABLE_OPTION = { type: 'message', message_id: -1 } as const;

function 同步当前在场到羁绊(data: z.infer<typeof Schema>): string[] {
  const 已同步: string[] = [];
  for (const [name, present] of Object.entries(data.在场 ?? {})) {
    const bond = data.羁绊?.[name];
    if (!bond || _.isEqual(bond, present)) continue;
    data.羁绊[name] = _.cloneDeep(present);
    已同步.push(name);
  }
  return 已同步;
}

export const useDataStore = defineMvuDataStore(Schema, VARIABLE_OPTION, data => {
  const 神契已迁移 = applyCanonicalShenqiEffects(data.value);
  const 已结算功法 = 结算已学习功法属性(data.value);
  const 已同步人物 = 同步当前在场到羁绊(data.value);
  if (!神契已迁移 && 已结算功法.length === 0 && 已同步人物.length === 0) return;

  updateVariablesWith(variables => {
    if (神契已迁移) {
      for (const [name, effect] of Object.entries(SHENQI_EFFECTS)) {
        const god = data.value.古神列表[name];
        if (!god) continue;
        _.set(variables, ['stat_data', '古神列表', name, '神契技能'], effect.技能);
        _.set(variables, ['stat_data', '古神列表', name, '神契描述'], god.神契描述);
      }
    }

    if (已结算功法.length > 0) {
      _.set(variables, ['stat_data', '主角', '六维'], _.cloneDeep(data.value.主角.六维));
      _.set(variables, ['stat_data', '$flag', '已结算功法属性'], [...data.value.$flag.已结算功法属性]);
      _.set(variables, ['stat_data', '功法'], _.cloneDeep(data.value.功法));
      _.set(variables, ['stat_data', '初始功法'], _.cloneDeep(data.value.初始功法));
    }

    if (已同步人物.length > 0) {
      _.set(variables, ['stat_data', '羁绊'], _.cloneDeep(data.value.羁绊));
      console.info('[修仙状态栏] 已用在场实时快照校准同名羁绊人物', 已同步人物);
    }

    return variables;
  }, VARIABLE_OPTION);
});
